/**
 * Enhanced Mock Data for M-Safety Dashboard
 * Supports multiple plants/factories (1, 2, 3)
 */

export interface CameraInfo {
  id: number;
  name: string;
  hasAlarm: boolean;
  lat: number;
  lng: number;
  plantId: number; // For filtering by factory
}

export interface SensorData {
  id: number;
  name: string;
  value: number;
  unit: string;
  history: { time: string; value: number }[];
  plantId: number; // For filtering by factory
}

// Helper to generate history
const generateHistory = (baseValue: number) => {
  return Array.from({ length: 24 }, (_, i) => ({
    time: `${i}:00`,
    value: baseValue + (Math.random() * 4 - 2),
  }));
};

