export interface EventInfo {
  id: number;
  time: string;
  title: string;
  type: "ALARM" | "INFO" | "SYSTEM";
  cameraId?: number | null;
  plantId: number;
}

export const mockEvents: EventInfo[] = Array.from({ length: 20 }, (_, i) => {
  const plantId = (i % 3) + 1;
  // pick a random camera from the same plant when available
  const cams = mockCameras.filter((c) => c.plantId === plantId);
  const cam =
    cams.length > 0 ? cams[Math.floor(Math.random() * cams.length)] : null;
  return {
    id: i + 1,
    time: `${String(12 - Math.floor(i / 2)).padStart(2, "0")}:${(i % 2) * 30}`,
    title: [
      "이상 접근 감지 (A구역)",
      "센서 데이터 임계치 초과",
      "일일 정기 점검 완료",
      "카메라 연결 일시 차단",
      "비인가 장치 감지",
      "화재 센서 정상 확인",
    ][i % 6],
    type: i % 3 === 0 ? "ALARM" : i % 3 === 1 ? "INFO" : "SYSTEM",
    plantId,
    cameraId: cam ? cam.id : null,
  } as EventInfo;
});

